+/// A candidate hit produced by a retrieval stage.
+#[derive(Debug, Clone, Copy, PartialEq, Serialize, Deserialize)]
+pub struct CandidateHit {
+    /// Document identifier.
+    pub doc_id: i64,
+    /// Stage-local score.
+    pub score: f64,
+}
+
+impl CandidateHit {
+    /// Construct a new candidate hit.
+    #[must_use]
+    pub const fn new(doc_id: i64, score: f64) -> Self {
+        Self { doc_id, score }
+    }
+}
