+fn redaction_zeroes_scores_and_marks_redacted() {
+    let config = ExplainComposerConfig {
+        verbosity: ExplainVerbosity::Detailed,
+        max_factors_per_stage: 10,
+    };
+    let mut hit = compose_hit_explanation(
